head.script:
scwin.login = $c.data.getMemInfo();
scwin.userId = scwin.login.userId;
scwin.privAdmin = scwin.login.privAdmin;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vLoginCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;
scwin.isSubCompany = false;

//hidden
scwin.txtCoClsCd = ""
scwin.modId = scwin.login.userId;
scwin.isChecked = true;


scwin.onpageload = function() {
    // 코드리스트
    const codeOptions = [
        { grpCd : "FM041", compID : "gr_paymgnt:payCycCd" },
        { grpCd : "ZZ522", compID : "gr_paymgnt:payDd" },
        { grpCd : "FM018", compID : "gr_paymgnt:payCntShtCd, lc_payCntShtCd", opt : {'range': '3,99'} },
        { grpCd : "ZZ006", compID : "gr_paymgnt:payCrcCd" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    scwin.f_setCompanyInfo();
    lc_payClsCd.setSelectedIndex(1);
    lc_confirmConYn.setSelectedIndex(2);
    lc_confirmAccYn_.setSelectedIndex(2);
    ed_draftRt.setValue(100)


}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {   
        // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU ;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');

} 


//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF) { 
    udc_companyInfo.cfCommonPopUp(scwin.udc_companyInfo_callBackFunc
                                ,ed_coCd.getValue(), ed_coNm.getValue()
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null);   
}

scwin.udc_companyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo("F");
};

scwin.udc_companyInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        ed_coCd.options.hidVal = rtnList[0];
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
    scwin.isSubCompany = true;
    }else{
        scwin.isSubCompany = false;
    } 	

    if(scwin.isChecked == true){    
        if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ){
            $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
            }
        else {
            $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);   
        }  
    }

    scwin.isChecked = false;
};

scwin.udc_companyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("")
    if (ed_coCd.getValue() != ""){

        scwin.f_PopUpCompanyInfo('T');
    }
};

scwin.udc_companyInfo_onviewchangeNameEvent = function (info) {
    ed_coCd.setValue("")
    if (ed_coNm.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {  
    // ds_condition.setUseChangeInfo(false);
    let ret = await $c.gus.cfValidate([ed_coCd])
    if (!ret)
        return

    $c.sbm.execute(sbm_retrievePaymgnt);
} 

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
// scwin.f_bankcd_Retrieve = function() {  
//     $c.sbm.execute(sbm_retrieveBankCd);
//   }
// sbm_retrievePaymgnt 서브미션에 은행코드, 은행명이 들어가있어서 해당 서브미션 삭제


//-------------------------------------------------------------------------
// 일괄적용함수
//-------------------------------------------------------------------------	
scwin.f_save = function() {
    scwin.f_WholeAdoption();
}

scwin.f_WholeAdoption = async function () {
    let cnt = 0;
	if ( ds_paymgnt.getRowCount() <= 0) {
		$c.win.alert("자료가 존재하지 않습니다.");
		return false;
	}
    for ( let i = 0 ; i < ds_paymgnt.getRowCount() ; i ++) {
        if (ds_paymgnt.getCellData(i, "selYn") == "1") {
            cnt++;

            ds_paymgnt.setCellData(i, "modId", scwin.modId);
            const prevBankCd = ds_paymgnt.getCellData(i, "bankCd");
            const changeBankCd = ed_changeBankCd.getValue();

            //변경은행 선택시
            if (prevBankCd === changeBankCd) {
                await $c.win.alert("이전은행과 변경은행이 같습니다. 다시 선택해 주십시오.");
                return;
            }
            if (changeBankCd == "") {
                await $c.win.alert("변경은행을 선택해 주십시오.");
                return;
            }
            ds_paymgnt.setCellData(i, "chgBankCd", changeBankCd);

            const draftRt = ds_paymgnt.getCellData(i, "draftRt");
            const confirmYn = ds_paymgnt.getCellData(i, "confirmYn");
            // 조건 불만족 시
            if (!(draftRt == 100.00 && confirmYn == "1")) {
                await $c.win.alert("어음 100%, 지급조건 확인여부, 지급계좌 확인여부가 '예'일 경우만 일괄적용 가능합니다.");
                return;
            }
        }
    }

    if ( cnt <= 0) {
        await $c.win.alert("일괄변경할 자료가 존재하지 않습니다.");
        return;
    }else {
        scwin.f_Save();
        return;
    }
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {  
    const confirm = await $c.win.confirm("일괄적용 하시겠습니까?");
    if (!confirm) return; 

    $c.sbm.execute(sbm_save);
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_InitObjects = function (e) {
    $c.gus.cfInitObjects(tbl_table1);
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 엑셀저장
//-------------------------------------------------------------------------
scwin.f_GridToExcel = async function() {
    if (ds_paymgnt.getRowCount() == 0) {
        await $c.win.alert("지급내역이 존재하지않습니다.");
        return;
    }
    let fileName = '지급은행 일괄변경';

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        await $c.data.downloadGridViewExcel(gr_paymgnt, { fileName: fileName + ".xlsx", sheetName: fileName });
    }
};


//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->은행 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function(select_code, txtCode, txtName, sFlag) {
    // let rtnList = null;
    // let sCmdName = "";
    let code = txtCode.getValue();
    let name = txtName.getValue();
    let param = ""

    switch (select_code) {
    // 귀속부서 PopUp 호출
    case '1':
        param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
        udc_acctDeptCdInfo6.cfCommonPopUp(scwin.udc_acctDeptCdInfo6_callBackFunc, code, name, sFlag, null, null,
                null, null, param, null, null, null, null, null, null,
                null, null); // 거래처			  
        break;
    // 거래처 PopUp 호출
    case '2':
        param = ",,," + ed_coCd.getValue();
        udc_clntList.cfCommonPopUp(scwin.udc_clntList_callBackFunc, code, name, sFlag, null, null,
                null, null, param, null, null, null, null, null, "F", null,
                null); // 거래처				 			  
        break;
    // 은행코드 PopUp 호출
    case '3':
        udc_bankCdInfo.cfCommonPopUp(scwin.udc_bankCdInfo_callBackFunc, code, name, sFlag, null, null,
                null, null, null, null, null, null, null, null, "F", null,
                null); // 은행
        break;
    // 변경 은행코드 PopUp 호출
    case '4':
        udc_changeBankCdInfo.cfCommonPopUp(scwin.udc_changeBankCdInfo_callBackFunc, code, name, sFlag, null, null,
                null, null, null, null, null, null, null, null, "F", null,
                null); // 은행
        break;
    }

    // if (rtnList != null) {
    //     if (rtnList[0] == "N/A")
    //         return;
    //     txtCode.setValue(rtnList[0]); // 코드
    //     txtName.setValue(rtnList[1]); // 코드명
    //     txtCode.options.hidVal = rtnList[0]; // 코드
    // } else {
    //     txtCode.setValue(""); // 코드
    //     txtName.setValue(""); // 코드명
    //     txtCode.options.hidVal = ""; // 코드
    // }
}

