// 서브미션
scwin.sbm_retrievePaymgnt_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    let rowCnt = ds_paymgnt.getRowCount();

	if ($c.gus.cfCheckCreateFlag() == true) {
      $c.gus.cfTurnCreateFlag(false);
    }
    else {    
      if (rowCnt == 0){
        await $c.win.alert("조회된 데이터가 없습니다");
	  }else{
  		totalRows.setValue(ds_paymgnt.getRowCount());
	  }
    }
}

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};


// grid decode format
scwin.draftDdCntCdDisplayFm = function(data) {
    return $c.gus.decode(data, "000", "", data);
}
